const data = $input.first().json.body;
const msg = (data.user_mssg || '').toLowerCase();

let conversationState = {};
try {
  const rawState = data.state || data.conversation_state;
  if (rawState) {
    conversationState = typeof rawState === 'string' ? JSON.parse(rawState) : rawState;
  }
} catch(e) {
  conversationState = {};
}

let phase = conversationState.phase || 'assessment';
let wizardStep = conversationState.wizard_step || 0;
let wizardData = conversationState.wizard_data || {};
let resp = '';
let status = 'Waiting';

if (phase === 'assessment') {
  if (msg.includes('1') || msg.includes('scratch') || msg.includes('build')) {
    phase = 'wizard';
    wizardStep = 1;
    resp = 'Perfect! Let us build your brand from scratch.\n\n**Question 1 of 6 - ATMOSPHERE**\n\nWhat is the overall vibe you want people to feel when they interact with your brand? Not how it looks, but how it FEELS.\n\nThink about the emotion, the energy, the mood. Are you warm and inviting? Bold and electric? Calm and grounding?';
  } else if (msg.includes('2') || msg.includes('import')) {
    phase = 'import';
    resp = 'Great choice! Paste your brand docs, website copy, or any existing brand materials. I will extract what matters and build your brand profile from it.';
  } else if (msg.includes('3') || msg.includes('chat')) {
    phase = 'advisor';
    resp = 'Cool, let us just chat! Ask me anything about branding - positioning, voice, visuals, messaging, hooks. What is on your mind?';
  } else {
    resp = 'Hey! I am Brandy. I help you build brands that actually sound like you.\n\nLet me check... looks like we have not defined your brand yet. Want to:\n\n1. **Build from scratch** - I will guide you through 6 quick questions\n2. **Import existing** - Got brand docs? Paste them and I will extract what matters\n3. **Just chat** - Ask me brand questions and we will figure it out as we go\n\nWhat works for you?';
  }
} else if (phase === 'wizard') {
  if (wizardStep === 1) {
    wizardData.atmosphere = data.user_mssg;
    wizardStep = 2;
    resp = 'Love that! I can feel it.\n\n**Question 2 of 6 - REBELLIOUS EDGE**\n\nWhat makes you different? What will you NOT compromise on?';
  } else if (wizardStep === 2) {
    wizardData.rebellious_edge = data.user_mssg;
    wizardStep = 3;
    resp = 'That is powerful.\n\n**Question 3 of 6 - ENEMY**\n\nWhat do you stand against? Not competitors - think industry BS, outdated practices, status quo.';
  } else if (wizardStep === 3) {
    wizardData.enemy_statement = data.user_mssg;
    wizardStep = 4;
    resp = 'YES. That clarity makes brands magnetic.\n\n**Question 4 of 6 - VISUALS**\n\nDescribe your visual vibe. Colors, energy, feel. Be unexpected.';
  } else if (wizardStep === 4) {
    wizardData.visual_direction = data.user_mssg;
    wizardStep = 5;
    resp = 'I can see it already.\n\n**Question 5 of 6 - HOOKS**\n\nHow do you grab attention? What makes people stop scrolling?';
  } else if (wizardStep === 5) {
    wizardData.hook_style = data.user_mssg;
    wizardStep = 6;
    resp = 'Great hook strategy.\n\n**Question 6 of 6 - MESSAGING**\n\nHow do you sound? Write like you talk. Show me your authentic voice.';
  } else if (wizardStep === 6) {
    wizardData.voice_messaging = data.user_mssg;
    wizardStep = 7;
    phase = 'summary';
    status = 'Ready';
    resp = '**YOUR BRAND FOUNDATION**\n\n- **Atmosphere:** ' + (wizardData.atmosphere || '') + '\n- **Rebellious Edge:** ' + (wizardData.rebellious_edge || '') + '\n- **Enemy:** ' + (wizardData.enemy_statement || '') + '\n- **Visuals:** ' + (wizardData.visual_direction || '') + '\n- **Hooks:** ' + (wizardData.hook_style || '') + '\n- **Voice:** ' + (wizardData.voice_messaging || '') + '\n\nThat is your foundation! Want me to generate a full brand bible?';
  }
}

const state = {
  phase: phase,
  brand_exists: false,
  wizard_step: wizardStep,
  wizard_data: wizardData,
  import_status: null
};

return [{
  json: {
    user_id: data.user_id,
    session_id: data.session_id,
    agent_name: 'brandy',
    timestamp_of_call_made: new Date().toISOString(),
    request_id: data.request_id,
    agent_response: resp,
    agent_status: status,
    state: state
  }
}];
